return items.map(item => {
  const body = item.json.body || {};
  const textRaw = body.text;

  if (!textRaw) {
    return {
      json: {
        ok: false,
        error: "Missing required field: text",
        example: { text: "Paste the job description here..." }
      }
    };
  }

  const text = String(textRaw).toLowerCase();

  const SKILLS = [
    "python", "sql", "fastapi", "flask", "django",
    "docker", "kubernetes", "aws", "azure", "gcp",
    "llm", "rag", "langchain", "vector", "chroma", "pinecone",
    "pytorch", "tensorflow", "pandas", "numpy",
    "etl", "airflow", "dbt", "spark",
    "mlops", "ci/cd", "github actions"
  ];

  const found = SKILLS
    .filter(s => text.includes(s.toLowerCase()))
    .map(s => s);

  return {
    json: {
      ok: true,
      found_skills: found,
      found_count: found.length,
      preview: textRaw.slice(0, 120) + (textRaw.length > 120 ? "..." : "")
    }
  };
});

return items.map(item => {
  // The OpenAI node returns a response object
  const response = item.json;

  // Extract assistant text from Responses API structure
  const text =
    response.output?.[0]?.content?.[0]?.text ||
    "No assistant text found.";

  // Try to parse JSON (since we instructed it to return JSON only)
  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    parsed = {
      ok: false,
      error: "Model did not return valid JSON",
      raw_output: text
    };
  }

  return {
    json: parsed
  };
});
